#!/usr/bin/env node
/**
 * Replaces generic-stub plans/alternatives entries with concrete,
 * position-specific content generated by Claude Haiku 4.5.
 *
 * Strategy:
 *  - Group plies by file + subline so each batch has shared context
 *    (opening name, color, prior moves)
 *  - Use prompt caching on the system prompt + opening context
 *  - Batch 10 plies per request to amortize per-call overhead
 *  - For each ply, generate 2-3 SHORT concrete plans (max ~15 words
 *    each) that name specific squares or pieces relevant to THAT
 *    position
 *
 * Output cache: docs/audit-runs/2026-05-19-content-scan/haiku-enrichments.json
 *
 * Idempotent: skips entries already present in the cache.
 *
 * Apply step (separate, run after this completes): stuff the cached
 * replacements back into the annotation files.
 */

import Anthropic from '@anthropic-ai/sdk';
import { readFile, writeFile, readdir, mkdir } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import { join } from 'node:path';
import { Chess } from 'chess.js';

const DIR = 'src/data/annotations';
const OUT_DIR = 'docs/audit-runs/2026-05-19-content-scan';
const CACHE_PATH = join(OUT_DIR, 'haiku-enrichments.json');
const MODEL = 'claude-haiku-4-5-20251001';
const BATCH_SIZE = 10;

const STUB_PLANS = new Set([
  'Complete piece development and prepare castling',
  'Fight for central control with pawns and pieces',
  'Convert the positional advantages into concrete gains',
  'Coordinate pieces for maximum effectiveness in the coming exchanges',
  'Improve piece placement and prepare the middlegame plan',
  'Look for pawn breaks to open lines for the active pieces',
  "Look for tactical opportunities to exploit the opponent's inaccuracy",
  'Maintain piece pressure while avoiding counter-tactics',
  "Be alert to the opponent's active ideas in this position",
  'Maintain solid piece coordination to neutralize threats',
  'Continue developing and improving piece placement',
  'Look for tactical opportunities',
]);

const STUB_ALT_RX = [
  /^Other (?:pawn|knight|bishop|rook|queen|king|piece) moves? (?:were|was) available/i,
  /^A different (?:pawn|knight|bishop|rook|queen) move was possible/i,
  /^The (?:pawn|knight|bishop|rook|queen|king) could go to other/i,
  /^(?:White|Black) had other options here/i,
  /^Other (?:moves|options) (?:were|are) available here/i,
  /^The (?:pawn|knight|bishop|rook|queen) had other (?:moves|options|squares)/i,
  /^Other (?:legal|reasonable) moves (?:were|are) possible/i,
];

function isStubAlt(s) {
  return typeof s === 'string' && STUB_ALT_RX.some((r) => r.test(s.trim()));
}

const SYSTEM_PROMPT = `You are a chess teacher writing concrete, position-specific narration for an annotated opening study. The student is reading the annotation as a move is played.

You will receive a batch of plies (half-moves) from a single opening line. For each ply, write:
- 2 SHORT concrete plans (max 14 words each) that name SPECIFIC squares or pieces relevant to THAT position. Use chess concepts the student can look at on the board.
- 1 SHORT concrete alternative move (max 14 words) — name a real alternative SAN in the format "SAN — brief reason".

NEVER use generic chess platitudes like "develop pieces", "fight for the center", "improve coordination", "look for tactical opportunities", "convert advantages", "complete development", "maintain pressure". These are banned phrases.

Every plan must reference at least one of: a specific square (e.g. "d4", "f7"), a specific piece (e.g. "dark-squared bishop", "queen's knight"), a specific structural feature (e.g. "isolated d-pawn", "open f-file"), or a specific tactical motif (e.g. "Nf5 outpost", "back-rank threat").

Output JSON in this exact shape:
{
  "plies": [
    { "ply": <number>, "plans": ["plan 1", "plan 2"], "alternative": "SAN — brief reason" }
  ]
}

Plans should be 8-14 words. Alternative should be 6-14 words. Be terse, concrete, and pedagogical.`;

const key = process.env.ANTHROPIC_KEY;
if (!key) {
  console.error('ANTHROPIC_KEY env var required');
  process.exit(1);
}
const client = new Anthropic({ apiKey: key });

async function ensureCache() {
  await mkdir(OUT_DIR, { recursive: true });
  if (existsSync(CACHE_PATH)) {
    return JSON.parse(await readFile(CACHE_PATH, 'utf-8'));
  }
  return { entries: {}, totals: { calls: 0, inputTokens: 0, outputTokens: 0, cacheReads: 0, cacheWrites: 0, costUSD: 0 } };
}

async function saveCache(cache) {
  await writeFile(CACHE_PATH, JSON.stringify(cache, null, 2));
}

function entryKey(file, sublineName, plyIdx) {
  return `${file}::${sublineName}::${plyIdx}`;
}

function moneyForUsage(usage) {
  // Haiku 4.5 pricing per million tokens (approx).
  const inCost = (usage.input_tokens || 0) / 1_000_000 * 1.0;
  const cacheReadCost = (usage.cache_read_input_tokens || 0) / 1_000_000 * 0.10;
  const cacheWriteCost = (usage.cache_creation_input_tokens || 0) / 1_000_000 * 1.25;
  const outCost = (usage.output_tokens || 0) / 1_000_000 * 5.0;
  return inCost + cacheReadCost + cacheWriteCost + outCost;
}

function fenAfterPly(sans, plyIdx) {
  const c = new Chess();
  for (let i = 0; i <= plyIdx; i++) {
    try { c.move(sans[i]); } catch { return null; }
  }
  return c.fen();
}

async function callHaiku(openingId, sublineName, color, contextPgn, ples) {
  // ples = [{ ply, san, fenBefore, fenAfter }]
  const userMsg = `Opening: ${openingId}\nLine: ${sublineName}\nStudent plays: ${color}\nPGN so far (truncated): ${contextPgn}\n\nGenerate plans + alternative for each of these plies:\n${ples.map((p) => `  ply ${p.ply}: SAN=${p.san}  FEN=${p.fenAfter}`).join('\n')}\n\nReturn JSON only.`;

  const res = await client.messages.create({
    model: MODEL,
    max_tokens: 1500,
    system: [
      { type: 'text', text: SYSTEM_PROMPT, cache_control: { type: 'ephemeral' } },
    ],
    messages: [{ role: 'user', content: userMsg }],
  });
  const text = res.content?.[0]?.text ?? '';
  let parsed = null;
  try {
    const jsonStart = text.indexOf('{');
    const jsonEnd = text.lastIndexOf('}');
    if (jsonStart !== -1 && jsonEnd !== -1) {
      parsed = JSON.parse(text.slice(jsonStart, jsonEnd + 1));
    }
  } catch (e) {
    console.warn('parse error:', e.message);
  }
  return { parsed, usage: res.usage };
}

async function main() {
  const cache = await ensureCache();
  let totalCallsMade = 0;
  let totalSpend = cache.totals?.costUSD || 0;
  const COST_CAP = parseFloat(process.env.COST_CAP_USD || '5.0');
  console.log(`[enrich] cost cap: $${COST_CAP.toFixed(2)} — start spend: $${totalSpend.toFixed(4)}`);

  const files = await readdir(DIR);
  const annotationFiles = files.filter((f) => f.endsWith('.json'));

  // Build work queue: [{file, openingId, sublineName, color, contextPgn, ples}]
  const queue = [];

  for (const fname of annotationFiles) {
    const fpath = join(DIR, fname);
    const doc = JSON.parse(await readFile(fpath, 'utf-8'));
    const openingId = doc.openingId;
    const color = (doc.color || 'white').toLowerCase();
    const baseSans = (doc.moveAnnotations || []).map((a) => a.san);

    function processSubline(arr, sublineName, contextSans, lineColor) {
      // Collect plies needing enrichment
      const stubPlies = [];
      for (let i = 0; i < (arr || []).length; i++) {
        const a = arr[i];
        const gPlans = (a.plans || []).filter((p) => STUB_PLANS.has((p || '').trim()));
        const gAlts = (a.alternatives || []).filter((alt) => isStubAlt(alt));
        if (gPlans.length === 0 && gAlts.length === 0) continue;
        const key = entryKey(fname, sublineName, i);
        if (cache.entries[key]) continue; // already done
        const fenAfter = fenAfterPly(arr.map((x) => x.san), i);
        if (!fenAfter) continue;
        stubPlies.push({ ply: i + 1, san: a.san, fenAfter, plyIdx: i });
      }
      if (stubPlies.length === 0) return;
      // Batch
      for (let start = 0; start < stubPlies.length; start += BATCH_SIZE) {
        const batch = stubPlies.slice(start, start + BATCH_SIZE);
        const contextPgn = contextSans.slice(0, Math.min(contextSans.length, batch[0].plyIdx)).join(' ');
        queue.push({
          file: fname, fpath, openingId, sublineName, color: lineColor || color,
          contextPgn, ples: batch,
        });
      }
    }

    processSubline(doc.moveAnnotations, '__main__', baseSans, color);
    for (const s of doc.subLines || []) {
      processSubline(s.moveAnnotations, s.name, (s.moveAnnotations || []).map((a) => a.san), color);
    }
  }

  console.log(`[enrich] ${queue.length} batches queued`);

  for (let i = 0; i < queue.length; i++) {
    if (totalSpend >= COST_CAP) {
      console.log(`[enrich] cost cap reached ($${totalSpend.toFixed(4)}) — halting`);
      break;
    }
    const item = queue[i];
    console.log(`[${i+1}/${queue.length}] ${item.file.replace('.json','')} :: ${item.sublineName} :: ${item.ples.length} plies`);
    try {
      const { parsed, usage } = await callHaiku(item.openingId, item.sublineName, item.color, item.contextPgn, item.ples);
      const cost = moneyForUsage(usage);
      totalSpend += cost;
      cache.totals.calls = (cache.totals.calls || 0) + 1;
      cache.totals.inputTokens = (cache.totals.inputTokens || 0) + (usage.input_tokens || 0);
      cache.totals.outputTokens = (cache.totals.outputTokens || 0) + (usage.output_tokens || 0);
      cache.totals.cacheReads = (cache.totals.cacheReads || 0) + (usage.cache_read_input_tokens || 0);
      cache.totals.cacheWrites = (cache.totals.cacheWrites || 0) + (usage.cache_creation_input_tokens || 0);
      cache.totals.costUSD = totalSpend;

      if (parsed?.plies) {
        for (const p of parsed.plies) {
          const matchingBatch = item.ples.find((b) => b.ply === p.ply);
          if (!matchingBatch) continue;
          const key = entryKey(item.file, item.sublineName, matchingBatch.plyIdx);
          cache.entries[key] = {
            ply: matchingBatch.ply,
            san: matchingBatch.san,
            plans: Array.isArray(p.plans) ? p.plans.slice(0, 3) : [],
            alternative: p.alternative || null,
          };
        }
      }
      totalCallsMade++;
      if (totalCallsMade % 20 === 0) {
        await saveCache(cache);
        console.log(`  spend so far: $${totalSpend.toFixed(4)}`);
      }
    } catch (e) {
      console.warn(`  err on batch ${i+1}: ${e.message}`);
    }
  }

  await saveCache(cache);
  console.log(`\n[enrich] DONE`);
  console.log(`  calls: ${cache.totals.calls}`);
  console.log(`  in tokens: ${cache.totals.inputTokens}, cache reads: ${cache.totals.cacheReads}, writes: ${cache.totals.cacheWrites}`);
  console.log(`  out tokens: ${cache.totals.outputTokens}`);
  console.log(`  spend: $${cache.totals.costUSD.toFixed(4)}`);
  console.log(`  cached entries: ${Object.keys(cache.entries).length}`);
}

main().catch((err) => { console.error('fatal:', err); process.exit(1); });
